import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedCode {

    public void processInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Properly encode user input before outputting it to the response
        String safeUserInput = encodeForHtml(userInput);

        response.getWriter().println("User input: " + safeUserInput);
    }

    private String encodeForHtml(String input) {
        if (input == null) {
            return "";
        }

        // Replace characters that have special meaning in HTML with their corresponding HTML entities
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
